INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('fire-eq-eng-moex-00131', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據各類場所消防安全設備檢修及申報作業基準之規定，下列之敘述何者錯誤？', '["進行自動撒水設備綜合檢查時，末端查驗管之放水壓力應在1 kgf／cm2以上10 kgf／cm2以下", "對二氧化碳滅火器及海龍滅火器進行重量檢查時，如失重超過10%以上或壓力表示值在綠色範圍 外時，應予以更新", "製造日期超過八年或無法辨識製造日期之乾粉滅火器，應予報廢", "第一種室內消防栓放水壓力應在1.7 kgf／cm2以上7 kgf／cm2以下"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00132', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據防焰性能認證實施要點之規定，一張材料防焰標示可申請多少張之窗簾物品防焰標示？', '["50", "100", "150", "200"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00133', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據各類場所消防安全設備設置標準之規定，有關室內消防栓之敘述何者錯誤？', '["室內消防栓設備之消防立管管系竣工時，應做加壓試驗，試驗壓力不得小於加壓送水裝置全閉揚 程一點五倍以上之水壓", "第一種消防栓各層任一點至消防栓接頭之水平距離在二十五公尺以下", "幫浦出水量，第一種消防栓每支每分鐘之水量在一百三十公升以上", "屋頂水箱之水量，第一種消防栓有零點五立方公尺以上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00134', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據消防法之規定，下列之敘述何者錯誤？', '["供公眾使用建築物之消防安全設備圖說，應由直轄市、縣（市）消防機關於主管建築機關許可開 工前，審查完成", "使用燃氣之熱水器及配管之承裝業自中華民國九十五年二月一日起使用燃氣熱水器之安裝，非經 僱用領有合格證照者，不得為之", "消防設備師或消防設備士為消防安全設備不實檢修報告者，處新臺幣三萬元以上十萬元以下罰鍰", "應設置消防安全設備之供營業使用場所其管理權人未依規定設置或維護，於發生火災時致人於死 者，處一年以上七年以下有期徒刑，得併科新臺幣一百萬元以上五百萬元以下罰金"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00135', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據消防法施行細則之規定，下列何者非屬於一定規模以上供公眾使用建築物？', '["總樓地板面積在三百平方公尺以上之百貨商場、超級市場及遊藝場等場所", "總樓地板面積在三百平方公尺以上之餐廳", "學校、總樓地板面積在二百平方公尺以上之補習班或訓練班", "總樓地板面積在五百平方公尺以上，其員工在三十人以上之工廠或機關（構）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00136', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據消防法施行細則之規定，防火管理人講習訓練時間不得少於多少小時？防火管理人每幾年至少 應接受講習訓練一次？', '["八小時，每二年", "八小時，每三年", "十六小時，每二年", "十六小時，每三年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00137', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法，室外儲槽場所儲槽儲存第四類公共 危險物品者，其防液堤之規定何者為錯誤？', '["室外儲槽之直徑未達十五公尺者，防液堤與儲槽壁板間之距離，不得小於儲槽高度之三分之一", "同一地區設有二座以上儲槽者，其周圍所設置防液堤之容量，應為最大之儲槽容量百分之一百一十 以上", "防液堤內面積不得超過八萬平方公尺", "室外儲槽容量在二萬公秉以上者，其防液堤應設置洩漏檢測設備，並應於可進行處置處所設置警 報設備"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00138', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法，室內儲槽場所之位置、構造及設備 之規定何者為錯誤？', '["儲槽專用室出入口應設置二十公分以上之門檻，或設置具有同等以上效能之防止流出措施", "儲槽專用室之儲槽與室內牆面之距離應在三十公分以上", "儲槽專用室之外牆有延燒之虞者，出入口應設置常時關閉式一小時以上防火時效之防火門", "儲槽容量不得超過管制量之四十倍，且第四類公共危險物品中之第二石油類及第三石油類，不得 超過二萬公升"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00139', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據液化石油氣容器認可作業及管理要點之規定，下列敘述何者錯誤？', '["試驗設備用壓力表或連成表應一年校正乙次", "型式認可之有效期限為三年，期限屆滿前三個月內得申請延展，每次延展期間為三年", "取得型式認可廠商之製造設施均應由專職人員擔任製造作業，確實紀錄液化石油氣容器製造相關 資料，並至少保存五年", "經型式認可者，應自取得型式認可書之日起三年內申請個別認可，經個別認可合格並取得液化石 油氣容器瓶身證明者，始得申購合格標示"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00140', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據防焰性能試驗基準之規定，下列之敘述何者錯誤？', '["展示用廣告板之餘焰時間不得超過十秒", "展示用廣告板之餘燃時間不得超過二十秒", "展示用廣告板之碳化面積不得超過五十平方公分", "展示用廣告板試體之點火加熱時間為二分鐘"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
